module QueryResult =
  struct
    type nonrec t =
      | PRESENT 
      | ABSENT 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | PRESENT -> "PRESENT"
      | ABSENT -> "ABSENT"
      | Non_static_id s -> s
    let of_string =
      function
      | "PRESENT" -> PRESENT
      | "ABSENT" -> ABSENT
      | x -> Non_static_id x
    let to_value x = `Enum (to_string x)
    let to_query v = to_query to_value v
    let to_header x = to_string x
    let of_xml xml_arg0 =
      of_string (string_of_xml ~kind:"enumeration QueryResult" xml_arg0)
    let of_json j = of_string (string_of_json ~kind:"QueryResult" j)
    let to_json = simple_to_json to_value
  end
